css += '\n';
css += '.me__license { font-size: 10px; color: #6f6f6f; line-height: 1.4; display: flex; align-items: center; gap: 4px; overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }';
css += '\n';
css += '.me__license-icon { display: inline-flex; align-items: center; color: #6f6f6f; cursor: pointer; }';
css += '\n';
