css += '.hdr { display: flex; align-items: center; height: 56px; background: #fff; padding: 0 20px; gap: 8px; flex-shrink: 0; }';
css += '\n';
css += '.hdr__left { display: flex; align-items: center; flex: 1; gap: 4px; min-width: 0; }';
css += '\n';
css += '.hdr__right { display: flex; align-items: center; flex: 1; justify-content: flex-end; gap: 4px; }';
css += '\n';

// ─── Base button ───
css += ".b { display: inline-flex; align-items: center; justify-content: center; cursor: pointer; border: none; outline: none; font-family: 'Segoe UI', sans-serif; transition: background 0.1s; }";
css += '\n';
css += '.b svg { display: block; flex-shrink: 0; }';
