css += '.b--picker .picker-chevron svg { width: 12px; height: 12px; }';
css += '\n';

// ─── Content area ───
css += '.content { flex: 1; display: flex; flex-direction: column; align-items: center; overflow-y: auto; }';
css += '\n';
css += '.content__inner { width: 820px; max-width: 820px; display: flex; flex-direction: column; gap: 45px; padding: 40px 0; transition: padding-top 0.15s ease; }';
css += '\n';

// ─── Greeting ───
css += ".greeting { font-size: 39px; line-height: 40px; text-align: left; font-family: Aptos, 'Segoe UI', sans-serif; padding: 0 100px; }";
