css += '.greeting__comma { font-weight: 300; color: #000; }';
css += '\n';
css += '.greeting__rest { font-weight: 300; color: #707070; }';
css += '\n';

// ─── Chat input ───
css += '.ci { display: flex; gap: 0; align-items: flex-start; width: 100%; }';
