// ─── Script ─────────────────────────────────────────────────────────

html += '<script>';


// Chat input interactivity
html += 'var ci = document.getElementById("chatInput");';
html += 'var ta = document.getElementById("textarea");';
html += 'var contentInner = document.querySelector(".content__inner");';
html += 'var contentArea = document.querySelector(".content");';
html += '\n';

// ZQ positioning: keep greeting+input centered, responsive to input height
html += 'var _padTop = 0;';
html += 'var _taLines = 1;';
html += 'function positionZQ() {';
html += '  if (document.querySelector(".shell").classList.contains("shell--sent")) return;';
html += '  var viewH = contentArea.clientHeight;';
html += '  contentInner.style.paddingTop = "0px";';
html += '  var innerH = contentInner.scrollHeight;';
html += '  var idealTop = Math.round(viewH * 0.25 + 40);';
html += '  var centeredTop = Math.round((viewH - innerH) * 0.42);';
html += '  var top = Math.max(40, Math.min(idealTop, centeredTop));';
html += '  _padTop = top;';
html += '  contentInner.style.paddingTop = top + "px";';
html += '}';
html += '\n';

html += 'function adjustForLines(oldLines, newLines) {';
html += '  var diff = newLines - oldLines;';
html += '  var shift = Math.round(diff * 18);';
html += '  var newPad = Math.max(40, _padTop - shift);';
html += '  _padTop = newPad;';
html += '  contentInner.style.paddingTop = newPad + "px";';
html += '}';
html += '\n';

html += 'function updateState() {';
html += '  var hasText = ta.value.trim().length > 0;';
html += '  var isFocused = document.activeElement === ta;';
html += '  ci.classList.toggle("ci--focused", isFocused);';
html += '  ci.classList.toggle("ci--has-text", hasText);';
html += '  ta.style.height = "auto";';
html += '  var lines = Math.max(1, Math.round(ta.scrollHeight / 36));';
html += '  ta.style.height = ta.scrollHeight + "px";';
html += '  if (lines !== _taLines) {';
html += '    var oldLines = _taLines;';
html += '    _taLines = lines;';
html += '    adjustForLines(oldLines, lines);';
html += '  }';
html += '}';
html += '\n';

html += 'ta.addEventListener("focus", updateState);';
html += 'ta.addEventListener("blur", updateState);';
html += 'ta.addEventListener("input", updateState);';
html += 'window.addEventListener("resize", positionZQ);';
html += 'positionZQ();';
html += 'updateState();';
html += '\n';

// Suggestion chips fill the chat input
html += 'document.querySelectorAll(".sc__chip").forEach(function(chip) {';
html += '  chip.addEventListener("click", function() {';
html += '    ta.value = chip.getAttribute("data-text");';
html += '    ta.focus();';
html += '    updateState();';
html += '  });';
html += '});';
html += '\n';

// Nav item select — single selection only
html += 'document.querySelectorAll(".nav .ni").forEach(function(el) {';
html += '  el.addEventListener("click", function() {';
html += '    document.querySelectorAll(".nav .ni.sel").forEach(function(s) { s.classList.remove("sel"); });';
html += '    el.classList.add("sel");';
html += '  });';
html += '});';
html += '\n';

// Nav collapse/expand toggle — Copilot logo button
html += 'var navEl = document.querySelector(".nav");';
html += 'document.getElementById("navToggle").addEventListener("click", function(e) {';
html += '  e.stopPropagation();';
html += '  navEl.classList.toggle("nav--collapsed");';
html += '});';
html += '\n';

// Add Menu toggle — click "+" to show/hide overlay + menu
html += 'var addBtn = document.getElementById("addBtn");';
html += 'var addBtn2 = document.getElementById("addBtn2");';
html += 'var amOverlay = document.getElementById("amOverlay");';
html += 'var addMenu = document.getElementById("addMenu");';
html += 'var mainEl = document.querySelector(".main");';
html += 'var activeAddBtn = addBtn;';
html += '\n';

html += 'function positionAddMenu() {';
html += '  var mainRect = mainEl.getBoundingClientRect();';
html += '  var btnRect = activeAddBtn.getBoundingClientRect();';
html += '  var inputEl = activeAddBtn.closest(".ci").querySelector(".ci__input");';
html += '  var inputRect = inputEl.getBoundingClientRect();';
html += '  var menuH = addMenu.offsetHeight;';
html += '  var btnCenterY = btnRect.top + btnRect.height / 2 - mainRect.top;';
html += '  var menuTop = btnCenterY - menuH / 2;';
html += '  var maxTop = mainRect.height - menuH - 40;';
html += '  if (menuTop > maxTop) { menuTop = maxTop; }';
html += '  if (menuTop < 0) { menuTop = 0; }';
html += '  var menuLeft = inputRect.left - mainRect.left;';
html += '  addMenu.style.left = menuLeft + "px";';
html += '  addMenu.style.top = menuTop + "px";';
html += '}';
html += '\n';

html += 'function openAddMenu() {';
html += '  amOverlay.classList.add("am-overlay--open");';
html += '  requestAnimationFrame(positionAddMenu);';
html += '}';
html += 'function closeAddMenu() { amOverlay.classList.remove("am-overlay--open"); }';
html += 'function toggleAddMenu(btn) {';
html += '  return function(e) {';
html += '    e.stopPropagation();';
html += '    activeAddBtn = btn;';
html += '    if (amOverlay.classList.contains("am-overlay--open")) { closeAddMenu(); } else { openAddMenu(); }';
html += '  };';
html += '}';
html += 'addBtn.addEventListener("click", toggleAddMenu(addBtn));';
html += 'addBtn2.addEventListener("click", toggleAddMenu(addBtn2));';
html += '\n';

// Work IQ toggle
html += 'var wiqToggle = document.getElementById("wiqToggle");';
html += 'if (wiqToggle) wiqToggle.addEventListener("click", function(e) {';
html += '  e.stopPropagation();';
html += '  wiqToggle.classList.toggle("off");';
html += '});';
html += '\n';

// Close add menu on overlay click (but not on menu itself)
html += 'amOverlay.addEventListener("click", function(e) {';
html += '  if (e.target === amOverlay) { closeAddMenu(); }';
html += '});';
html += '\n';

// Close on Escape key
html += 'document.addEventListener("keydown", function(e) {';
html += '  if (e.key === "Escape") { closeAddMenu(); closeSources(); }';
html += '});';
html += '\n';
// ─── Sources panel ───
html += 'var srcOverlay = document.getElementById(\"srcOverlay\");';
html += 'var srcDismiss = document.getElementById(\"srcDismiss\");';
html += 'var changeDsBtn = document.getElementById(\"changeDsBtn\");';
html += '\n';

html += 'function openSources() { srcOverlay.classList.add(\"src-overlay--open\"); }';
html += 'function closeSources() { srcOverlay.classList.remove(\"src-overlay--open\"); }';
html += '\n';

// "Change data sources" in add menu → instant swap (no frost gap)
html += 'changeDsBtn.addEventListener(\"click\", function(e) {';
html += '  e.stopPropagation();';
html += '  var srcPanel = srcOverlay.querySelector(\".src-panel\");';
html += '  srcOverlay.style.transition = \"none\";';
html += '  amOverlay.style.transition = \"none\";';
html += '  if (srcPanel) srcPanel.style.transition = \"none\";';
html += '  srcOverlay.classList.add(\"src-overlay--open\");';
html += '  amOverlay.classList.remove(\"am-overlay--open\");';
html += '  void srcOverlay.offsetHeight;';
html += '  srcOverlay.style.transition = \"\";';
html += '  amOverlay.style.transition = \"\";';
html += '  if (srcPanel) srcPanel.style.transition = \"\";';
html += '});';
html += '\n';

// Dismiss × button closes sources
html += 'srcDismiss.addEventListener(\"click\", function() { closeSources(); });';
html += '\n';

// Click outside sources panel closes it
html += 'srcOverlay.addEventListener(\"click\", function(e) {';
html += '  if (e.target === srcOverlay) { closeSources(); }';
html += '});';
html += '\n';

// Toggle switches inside sources panel
html += 'document.querySelectorAll(\".src-list .tgl-track\").forEach(function(el) {';
html += '  el.addEventListener(\"click\", function() { el.classList.toggle(\"tgl-track--on\"); });';
html += '});';
html += '\n';
// ─── Send transition: greeting → response ───
html += 'var shell = document.querySelector(".shell");';
html += 'var sendBtn = document.getElementById("sendBtn");';
html += 'var userMsgText = document.getElementById("userMsgText");';
html += '\n';

html += 'function doSend() {';
html += '  var text = ta.value.trim();';
html += '  if (!text) return;';
html += '  userMsgText.textContent = text;';
html += '  ta.value = "";';
html += '  updateState();';
html += '  shell.classList.remove("shell--responded");';
html += '  document.getElementById("skipThinking").classList.remove("skip-thinking--visible");';
html += '  document.getElementById("responseText").classList.remove("response-text--visible");';
html += '  document.getElementById("thinkingRow").style.display = "";';
html += '  shell.classList.add("shell--sent");';
html += '\n';
html += '  setTimeout(function() { var ct = document.querySelector(".content"); var msg = document.getElementById("userMsg"); ct.scrollTop = msg.offsetTop - ct.offsetTop; }, 100);';
html += '\n';
html += '  clearTimeout(window._skipTimer);';
html += '  window._skipTimer = setTimeout(function() {';
html += '    document.getElementById("skipThinking").classList.add("skip-thinking--visible");';
html += '  }, 2000);';
html += '}';
html += '\n';

// Click send button
html += 'sendBtn.addEventListener("click", function() { doSend(); });';
html += '\n';

// Press Enter to send (Shift+Enter for newline)
html += 'ta.addEventListener("keydown", function(e) {';
html += '  if (e.key === "Enter" && !e.shiftKey) {';
html += '    e.preventDefault();';
html += '    doSend();';
html += '  }';
html += '});';
html += '\n';

// Footer send button state management
html += 'var footerBtn = document.getElementById("footerSendBtn");';
html += 'var fStop = document.getElementById("fSendStop");';
html += 'var fEq = document.getElementById("fSendEq");';
html += 'var fArrow = document.getElementById("fSendArrow");';
html += 'var ta2 = document.getElementById("textarea2");';
html += '\n';

html += 'function setFooterBtn(mode) {';
html += '  fStop.style.display = mode === "stop" ? "" : "none";';
html += '  fEq.style.display = mode === "eq" ? "" : "none";';
html += '  fArrow.style.display = mode === "send" ? "" : "none";';
html += '  footerBtn.className = mode === "stop" ? "b b--ilg b--stop" : mode === "send" ? "b b--ilg b--primary" : "b b--ilg b--secondary";';
html += '  footerBtn.title = mode === "stop" ? "Stop" : mode === "send" ? "Send" : "Copilot";';
html += '}';
html += '\n';

// textarea2 input toggles eq ↔ send
html += 'ta2.addEventListener("input", function() {';
html += '  var hasText = ta2.value.trim().length > 0;';
html += '  if (shell.classList.contains("shell--responded")) {';
html += '    setFooterBtn(hasText ? "send" : "eq");';
html += '  }';
html += '});';
html += '\n';

// Stop/Send button click
html += 'var stopBtn = footerBtn;';
html += 'function resetChat() {';
html += '  shell.classList.remove("shell--sent");';
html += '  shell.classList.remove("shell--responded");';
html += '  document.getElementById("skipThinking").classList.remove("skip-thinking--visible");';
html += '  document.getElementById("responseText").classList.remove("response-text--visible");';
html += '  document.getElementById("responseFooter").classList.remove("rf--visible");';
html += '  document.querySelectorAll(".rf__btn--active").forEach(function(b) { b.classList.remove("rf__btn--active"); });';
html += '  document.getElementById("thinkingRow").style.display = "";';
html += '  clearTimeout(window._skipTimer);';
html += '  ta.value = "";';
html += '  ta2.value = "";';
html += '  setFooterBtn("stop");';
html += '  updateState();';
html += '  closeAddMenu();';
html += '}';
html += '\n';

html += 'footerBtn.addEventListener("click", function() {';
html += '  if (fStop.style.display !== "none") {';
html += '    resetChat();';
html += '  } else if (fArrow.style.display !== "none") {';
html += '    doSendFromFooter();';
html += '  }';
html += '});';
html += '\n';

// Send from footer textarea (appends new message + thinking)
html += 'function doSendFromFooter() {';
html += '  var text = ta2.value.trim();';
html += '  if (!text) return;';
html += '  var rv = document.getElementById("responseView");';
html += '  var thinkRow = document.getElementById("thinkingRow");';
html += '  var respText = document.getElementById("responseText");';
html += '  var skipBtn = document.getElementById("skipThinking");';
// Persist the current response: clone it as a static block before thinkRow
html += '  if (responseEl.style.display === "block" && responseEl.innerHTML.trim()) {';
html += '    var clone = responseEl.cloneNode(true);';
html += '    clone.removeAttribute("id");';
html += '    clone.style.display = "block";';
html += '    clone.className = "response-text response-text--visible";';
html += '    var cur = clone.querySelector(".stream-cursor"); if (cur) cur.remove();';
html += '    rv.insertBefore(clone, thinkRow);';
html += '  }';
// Hide the template response text
html += '  responseEl.style.display = "none";';
html += '  responseEl.innerHTML = "";';
html += '  shell.classList.remove("shell--responded");';
html += '  skipBtn.classList.remove("skip-thinking--visible");';
// Create new user bubble after the persisted response
html += '  var bubble = document.createElement("div");';
html += '  bubble.className = "user-msg";';
html += '  bubble.innerHTML = \'<div class="user-msg__bubble">\' + text + \'</div>\';';
html += '  rv.insertBefore(bubble, thinkRow);';
html += '\n';
html += '  setTimeout(function() { var ct = document.querySelector(".content"); ct.scrollTop = bubble.offsetTop - ct.offsetTop; }, 100);';
html += '\n';
// Reset thinking row
html += '  thinkRow.style.display = "";';
html += '  respText.classList.remove("response-text--visible");';
html += '  ta2.value = "";';
html += '  setFooterBtn("stop");';
// Show skip thinking after 2s
html += '  window._skipTimer = setTimeout(function() {';
html += '    skipBtn.classList.add("skip-thinking--visible");';
html += '  }, 2000);';
html += '}';
html += '\n';

// Enter to send from footer textarea
html += 'ta2.addEventListener("keydown", function(e) {';
html += '  if (e.key === "Enter" && !e.shiftKey) {';
html += '    e.preventDefault();';
html += '    if (fArrow.style.display !== "none") doSendFromFooter();';
html += '  }';
html += '});';
html += '\n';

// Skip Thinking → stream response with typewriter animation
html += 'var responseEl = document.getElementById("responseText");';
html += 'var fullResponseHTML = responseEl.innerHTML;';
html += 'responseEl.innerHTML = "";';
html += '\n';

html += 'function streamResponse() {';
html += '  shell.classList.add("shell--responded");';
html += '  responseEl.style.display = "block";';
html += '  responseEl.innerHTML = "";';
html += '  var temp = document.createElement("div");';
html += '  temp.innerHTML = fullResponseHTML;';
html += '  var allText = temp.textContent || "";';
html += '  var words = allText.split(/\\s+/);';
html += '  var htmlParts = fullResponseHTML;';
html += '  var charIdx = 0;';
html += '  var wordIdx = 0;';
html += '  var cursor = document.createElement("span");';
html += '  cursor.className = "stream-cursor";';
html += '  function nextChunk() {';
html += '    if (wordIdx >= words.length) { if (cursor.parentNode) cursor.remove(); document.getElementById("responseFooter").classList.add("rf--visible"); return; }';
html += '    var step = 3 + Math.floor(Math.random() * 8);';
html += '    if (step > words.length - wordIdx) step = words.length - wordIdx;';
html += '    var charCount = 0;';
html += '    for (var s = 0; s < step; s++) { charCount += words[wordIdx + s].length + 1; }';
html += '    charIdx += charCount;';
html += '    wordIdx += step;';
html += '    var partial = htmlParts;';
html += '    var textSoFar = words.slice(0, wordIdx).join(" ");';
html += '    var shown = 0; var cutIdx = 0;';
html += '    for (var i = 0; i < partial.length && shown < textSoFar.length; i++) {';
html += '      if (partial[i] === "<") { while (i < partial.length && partial[i] !== ">") i++; continue; }';
html += '      if (partial[i] === "&") { while (i < partial.length && partial[i] !== ";") i++; shown++; cutIdx = i + 1; continue; }';
html += '      shown++; cutIdx = i + 1;';
html += '    }';
html += '    var visibleHTML = partial.substring(0, cutIdx);';
html += '    var openTags = [];';
html += '    visibleHTML.replace(/<\\/?([a-zA-Z][a-zA-Z0-9]*)[^>]*>/g, function(m, tag) {';
html += '      if (m[1] !== "/") openTags.push(tag); else if (openTags.length && openTags[openTags.length-1] === tag) openTags.pop();';
html += '    });';
html += '    var closers = ""; for (var t = openTags.length - 1; t >= 0; t--) closers += "</" + openTags[t] + ">";';
html += '    responseEl.innerHTML = visibleHTML + closers;';
html += '    responseEl.appendChild(cursor);';
html += '    setTimeout(nextChunk, 12 + Math.floor(Math.random() * 18));';
html += '  }';
html += '  nextChunk();';
html += '}';
html += '\n';

html += 'document.getElementById("skipThinking").addEventListener("click", function() {';
html += '  clearTimeout(window._skipTimer);';
html += '  setFooterBtn("eq");';
html += '  streamResponse();';
html += '});';
html += '\n';

// Response footer: Copy toast + Like/Dislike mutually exclusive toggle
html += 'document.querySelector(".rf__btn--copy").addEventListener("click", function() {';
html += '  var toast = document.getElementById("rfToast");';
html += '  toast.classList.add("rf__toast--visible");';
html += '  setTimeout(function() { toast.classList.remove("rf__toast--visible"); }, 1500);';
html += '});';
html += '\n';
html += 'document.querySelectorAll(".rf__btn--like, .rf__btn--dislike").forEach(function(btn) {';
html += '  btn.addEventListener("click", function() {';
html += '    var footer = btn.closest(".rf");';
html += '    var isLike = btn.classList.contains("rf__btn--like");';
html += '    var sibling = footer.querySelector(isLike ? ".rf__btn--dislike" : ".rf__btn--like");';
html += '    if (btn.classList.contains("rf__btn--active")) {';
html += '      btn.classList.remove("rf__btn--active");';
html += '    } else {';
html += '      btn.classList.add("rf__btn--active");';
html += '      if (sibling) sibling.classList.remove("rf__btn--active");';
html += '    }';
html += '  });';
html += '});';
html += '\n';

// New chat button → reset to fresh state
html += 'document.getElementById("newChatBtn").addEventListener("click", function(e) {';
html += '  e.stopPropagation();';
html += '  resetChat();';
html += '});';
html += '\n';

html += '</script>';

html += '</body>';
html += '</html>';

